CONTRACT_SCHEMA = "foxai.agent_fox.technical_core.evidence_contract.v1"
DEFAULT_INPUT = Path(
    r"Z:\FOXAI\System\EngineeringWorkshop\missions\ENG-20260721-042128-CF3008_V1A0_R2_STATIC_AUDIT"
)
DEFAULT_OUTPUT = Path(
    r"Z:\FOXAI\System\EngineeringWorkshop\missions\ENG-20260721-051832-1CAA3F_V1A1_NORMALIZED"
)
DEFAULT_PROJECT_ROOT = Path(r"Z:\FOXAI")
MAX_INPUT_FILE_BYTES = 8 * 1024 * 1024
MAX_OUTPUT_BYTES = 24 * 1024 * 1024
MAX_HASH_BYTES = 16 * 1024 * 1024
REQUIRED_INPUTS = (
    "AUDIT_RECEIPT.json",
    "GAPS_AND_WARNINGS.json",
    "LAUNCHER_TRACE_CANDIDATES.json",
    "LIVE_STATIC_MANIFEST.json",
