    "NORMALIZATION_RECEIPT.json",
)
MODEL_SUFFIXES = {".gguf", ".safetensors", ".ckpt", ".pt", ".pth", ".onnx"}
DATABASE_SUFFIXES = {".db", ".sqlite", ".sqlite3"}
INDEX_SUFFIXES = {".index", ".faiss"}
LAUNCHER_SUFFIXES = {".bat", ".cmd", ".ps1", ".vbs", ".lnk"}
PACKAGE_SUFFIXES = {".zip", ".whl", ".7z", ".tar", ".gz"}
UNRESOLVED_VAR_RE = re.compile(r"%(?:~[A-Za-z0-9]+|[^%]+)%", re.IGNORECASE)
ASSIGNMENT_REFERENCE_RE = re.compile(
    r"(?:^|\\)(?:COMFY_PYTHON|PORTABLE_PY|PORTABLE_PYTHON|PY|PYTHON|PYTHON_CMD|PYTHON_EXE|PYTHONW)=[A-Za-z]:\\",
    re.IGNORECASE,
)
TIMESTAMP_RE = re.compile(r"(?:19|20)\d{6}(?:T\d{6,})?", re.IGNORECASE)
HASH_RE = re.compile(r"^[0-9a-f]{64}$", re.IGNORECASE)


def canonical_bytes(value: Any) -> bytes:
    return (json.dumps(value, ensure_ascii=False, sort_keys=True, separators=(",", ":")) + "\n").encode("utf-8")


def pretty_bytes(value: Any) -> bytes:
    return (json.dumps(value, ensure_ascii=False, sort_keys=True, indent=2) + "\n").encode("utf-8")


def sha256_bytes(data: bytes) -> str:
    return hashlib.sha256(data).hexdigest()


def sha256_file(path: Path, limit: int | None = None) -> str:
    size = path.stat().st_size
    if limit is not None and size > limit:
        raise ValueError(f"hash_input_over_limit:{path}:{size}")
    digest = hashlib.sha256()
    with path.open("rb") as handle:
        for chunk in iter(lambda: handle.read(1024 * 1024), b""):
            digest.update(chunk)
    return digest.hexdigest()


def norm_win(value: str | Path | None) -> str:
    if value is None:
        return ""
    return str(value).replace("/", "\\").strip()


def casefold_path(value: str | Path | None) -> str:
    return norm_win(value).casefold().rstrip("\\")


def relative_from_root(path_text: str, project_root: str = r"Z:\FOXAI") -> str | None:
    path_norm = norm_win(path_text)
    root_norm = norm_win(project_root).rstrip("\\")
    if path_norm.casefold() == root_norm.casefold():
        return ""
    prefix = root_norm + "\\"
    if path_norm.casefold().startswith(prefix.casefold()):
        return path_norm[len(prefix):]
    return None


def path_parts(path_text: str, project_root: str = r"Z:\FOXAI") -> list[str]:
    relative = relative_from_root(path_text, project_root)
    candidate = relative if relative is not None else norm_win(path_text)
    return [part for part in PureWindowsPath(candidate).parts if part not in {"\\", "/"}]


def has_part(parts: Iterable[str], names: set[str]) -> bool:
    lowered = {part.casefold() for part in parts}
    return bool(lowered & {name.casefold() for name in names})


def contains_fragment(parts: Iterable[str], fragments: Iterable[str]) -> bool:
    lowered = [part.casefold() for part in parts]
    return any(fragment.casefold() in part for part in lowered for fragment in fragments)


def unresolved_reference_reason(path_text: str) -> str | None:
    value = norm_win(path_text)
    if UNRESOLVED_VAR_RE.search(value) or "%~" in value:
        return "unresolved_batch_variable"
    if ASSIGNMENT_REFERENCE_RE.search(value):
        return "malformed_assignment_captured_as_path"
    if "\\..\\" in value or value.endswith("\\.."):
        return "relative_parent_reference_not_resolved"
    if '"' in value or "\x00" in value:
        return "malformed_path_text"
    return None


def historical_location(parts: list[str]) -> tuple[bool, str | None]:
    lower = [part.casefold() for part in parts]
    exact_groups = {
        "archive": {"archive", "archives", "archived"},
        "backup": {"backup", "backups"},
        "snapshot": {"snapshot", "snapshots", "baseline", "baselines"},
        "receipt": {"receipt", "receipts"},
        "mission_workspace": {"missions", "previews"},
        "package": {"package", "packages", "packaging", "dist", "build", "wheelhouse"},
    }
    for category, names in exact_groups.items():
        if any(part in names for part in lower):
            return True, category
    if any("quarantine" in part for part in lower):
        return True, "archive"
    if any(part.startswith("agent_fox_v1a") for part in lower):
        return True, "package"
    if len(lower) > 1:
        top = lower[0]
        package_signal = re.search(
            r"(?:^|_)(?:apply|preflight|integration|hotfix|patch|install|package|build|preview|seal|closure|enablement|activation|migration|repair|fix)(?:_|$)",
            top,
        )
        versioned_bundle = re.match(r"^(?:usbc?\d|pr\d|emi\d|ems\d|vit\d)", top)
        named_versioned_bundle = (top.startswith("foxai_") or top.startswith("kayocks_")) and re.search(r"(?:^|_)v\d", top)
        if package_signal or versioned_bundle or named_versioned_bundle:
            return True, "package"
    return False, None


def classify_path(path_text: str, *, suffix: str | None = None, protected: bool = False) -> dict[str, Any]:
    normalized = norm_win(path_text)
    parts = path_parts(normalized)
    lower_parts = [part.casefold() for part in parts]
    ext = (suffix or PureWindowsPath(normalized).suffix).casefold()
    unresolved = unresolved_reference_reason(normalized)
    is_historical, historical_kind = historical_location(parts)

    categories: list[str] = []
    if unresolved:
        categories.append("unresolved_reference")
    if protected:
        categories.append("protected_location")
    if historical_kind:
        categories.append(historical_kind)
    if ext in LAUNCHER_SUFFIXES:
        categories.append("launcher")
    if ext in MODEL_SUFFIXES:
        categories.append("model")
    if ext in DATABASE_SUFFIXES:
        categories.append("database")
    if ext in INDEX_SUFFIXES or any(part == "index" or part.endswith("_index") for part in lower_parts):
        categories.append("index")
    if ext in PACKAGE_SUFFIXES:
        categories.append("package")
    if has_part(parts, {"runtime", ".venv", "venv", "env", "site-packages", "python_embeded"}):
        categories.append("runtime")
    if contains_fragment(parts, {"output", "reports", "logs", "generated", "export"}):
        categories.append("generated_output")
    if has_part(parts, {"writing", "my writing", "my poems", "legacy work", "personal"}):
        categories.append("personal_content")

    if not is_historical and not unresolved:
        categories.append("live_candidate")

    precedence = (
        "unresolved_reference",
        "receipt",
        "snapshot",
        "backup",
        "archive",
        "mission_workspace",
        "package",
        "protected_location",
        "model",
        "database",
        "index",
        "launcher",
        "runtime",
        "generated_output",
        "personal_content",
        "live_candidate",
    )
    unique_categories = [item for item in precedence if item in set(categories)]
    primary = unique_categories[0] if unique_categories else "unclassified"
    return {
        "normalized_path": normalized,
        "relative_path": relative_from_root(normalized),
        "primary_category": primary,
        "categories": unique_categories,
        "historical_or_derived_location": is_historical,
        "unresolved_reason": unresolved,
    }


def evidence_class_for(path_info: dict[str, Any], *, source_kind: str) -> str:
    categories = set(path_info["categories"])
    if "unresolved_reference" in categories:
        return "missing_evidence"
    if "receipt" in categories:
        return "historical_receipt"
    if "snapshot" in categories or "backup" in categories:
        return "known_good_baseline"
    if source_kind == "repository_reference":
        return "repository_reference"
    if source_kind == "declared_manifest":
        return "declared_manifest"
    if source_kind == "static_source":
        return "static_live_source" if "live_candidate" in categories else "known_good_baseline"
    return "observed_live" if "live_candidate" in categories else "known_good_baseline"


def load_inputs(input_dir: Path) -> tuple[dict[str, Any], dict[str, str]]:
    data: dict[str, Any] = {}
    hashes: dict[str, str] = {}
    for name in REQUIRED_INPUTS:
        path = input_dir / name
        if not path.is_file():
            raise FileNotFoundError(f"required_input_missing:{path}")
        size = path.stat().st_size
        if size > MAX_INPUT_FILE_BYTES:
            raise ValueError(f"required_input_over_limit:{path}:{size}")
        raw = path.read_bytes()
        data[name] = json.loads(raw.decode("utf-8-sig"))
        hashes[name] = sha256_bytes(raw)
    return data, hashes


def verify_input_contract(data: dict[str, Any]) -> None:
    receipt = data["AUDIT_RECEIPT.json"]
    manifest = data["LIVE_STATIC_MANIFEST.json"]
    launchers = data["LAUNCHER_TRACE_CANDIDATES.json"]
    runtimes = data["PYTHON_RUNTIME_STATIC_MAP.json"]
    reusable = data["REUSABLE_COMPONENTS_MAP.json"]
    mission_index = data["MISSION_EVIDENCE_INDEX.json"]
    if receipt.get("result") != "static_baseline_complete":
        raise ValueError("source_audit_not_complete")
    for flag in ("network_used", "packages_installed", "live_foxai_source_modified", "models_loaded"):
        if receipt.get(flag) is not False:
            raise ValueError(f"source_audit_safety_flag_invalid:{flag}")
    if manifest.get("protected_candidates_unchanged", {}).get("unchanged") is not True:
        raise ValueError("source_protected_candidates_not_unchanged")
    if launchers.get("launcher_count") != len(launchers.get("launchers", [])):
        raise ValueError("launcher_count_mismatch")
    if runtimes.get("runtime_count") != len(runtimes.get("runtimes", [])):
        raise ValueError("runtime_count_mismatch")
    if reusable.get("component_count") != len(reusable.get("components", [])):
        raise ValueError("component_count_mismatch")
    if mission_index.get("record_count") != len(mission_index.get("records", [])):
        raise ValueError("mission_record_count_mismatch")


def protected_path_set(manifest: dict[str, Any]) -> set[str]:
    result = set()
    for item in manifest.get("protected_candidates", []):
        path = item.get("path")
        if path:
            result.add(casefold_path(path))
    return result


def normalize_top_level(manifest: dict[str, Any], protected: set[str]) -> list[dict[str, Any]]:
    records = []
    for item in manifest.get("top_level_inventory", []):
        path = item.get("path", "")
        info = classify_path(path, suffix=item.get("suffix"), protected=casefold_path(path) in protected)
        record = dict(item)
        record["path_classification"] = info
        record["evidence_class"] = evidence_class_for(info, source_kind="observed_metadata")
        records.append(record)
    records.sort(key=lambda item: casefold_path(item.get("path")))
    return records


def launcher_group_key(item: dict[str, Any]) -> str:
    path = item.get("relative_path") or item.get("path") or ""
    name = PureWindowsPath(norm_win(path)).name.casefold()
    size = item.get("size_bytes")
    suffix = item.get("suffix", "").casefold()
    return f"{name}|{suffix}|{size if isinstance(size, int) else 'unknown'}"


def classify_launchers(source: dict[str, Any], protected: set[str]) -> dict[str, Any]:
    unique_by_path: dict[str, dict[str, Any]] = {}
    for item in source.get("launchers", []):
        key = casefold_path(item.get("path"))
        if key and key not in unique_by_path:
            unique_by_path[key] = item

    normalized: list[dict[str, Any]] = []
    groups: dict[str, list[str]] = defaultdict(list)
    for item in unique_by_path.values():
        path = item.get("path", "")
        info = classify_path(path, suffix=item.get("suffix"), protected=casefold_path(path) in protected)
        relative = item.get("relative_path") or info.get("relative_path") or ""
        is_root_level = bool(relative) and "\\" not in norm_win(relative).strip("\\")
        group_key = launcher_group_key(item)
        groups[group_key].append(path)
        normalized.append({
            "path": path,
            "relative_path": relative,
            "size_bytes": item.get("size_bytes"),
            "modified_ns": item.get("modified_ns"),
            "suffix": item.get("suffix"),
            "parse_status": item.get("parse_status"),
            "path_classification": info,
            "evidence_class": evidence_class_for(info, source_kind="static_source"),
            "root_level": is_root_level,
            "same_name_size_group_key": group_key,
            "copy_status": "candidate_group_only_not_content_proof",
            "execution_performed": item.get("execution_performed") is True,
            "interesting_line_count": len(item.get("interesting_lines", [])),
            "path_token_count": len(item.get("path_tokens", [])),
        })
    normalized.sort(key=lambda item: casefold_path(item["path"]))

    group_records = []
    for key, paths in sorted(groups.items(), key=lambda pair: pair[0]):
        if len(paths) > 1:
            group_records.append({
                "group_key": key,
                "paths": sorted(paths, key=str.casefold),
                "count": len(paths),
                "status": "possible_copies_grouped_by_filename_suffix_and_size_only",
                "content_identity_proven": False,
            })

    category_counts = Counter(item["path_classification"]["primary_category"] for item in normalized)
    evidence_counts = Counter(item["evidence_class"] for item in normalized)
    return {
        "schema": NORMALIZER_SCHEMA,
        "source_launcher_count": source.get("launcher_count"),
        "unique_path_count": len(normalized),
        "root_level_count": sum(1 for item in normalized if item["root_level"]),
        "live_candidate_count": sum(
            1 for item in normalized if "live_candidate" in item["path_classification"]["categories"]
        ),
        "historical_or_derived_count": sum(
            1 for item in normalized if item["path_classification"]["historical_or_derived_location"]
        ),
        "primary_category_counts": dict(sorted(category_counts.items())),
        "evidence_class_counts": dict(sorted(evidence_counts.items())),
        "possible_copy_groups": group_records,
        "copy_group_warning": "Filename, suffix, and size similarity is not proof of identical content.",
        "launchers": normalized,
    }


def runtime_reference_status(item: dict[str, Any]) -> tuple[str, str]:
    path = norm_win(item.get("path"))
    unresolved = unresolved_reference_reason(path)
    if unresolved:
        return unresolved, "not_installed_runtime"
    if item.get("kind") == "file" and item.get("suffix", "").casefold() == ".exe" and not item.get("error"):
        return "actual_existing_executable_file", "installed_runtime_candidate"
    error = str(item.get("error") or "")
    if "FileNotFoundError" in error:
        return "literal_path_not_found", "not_installed_runtime"
    if "OSError" in error:
        return "invalid_literal_path", "not_installed_runtime"
    return "unresolved_static_record", "not_installed_runtime"


def runtime_owner(path_text: str) -> str:
    path = casefold_path(path_text)
    if "\\runtime\\comfyui\\" in path or "\\comfyui\\" in path:
        return "ComfyUI"
    if "\\runtime\\desktop\\" in path:
        return "Desktop"
    if "\\runtime\\core\\" in path:
        return "Core"
    if "\\.venv\\" in path:
        return "virtual_environment"
    if "\\env\\" in path:
        return "legacy_or_general_env"
    return "unresolved"


def classify_runtimes(source: dict[str, Any]) -> dict[str, Any]:
    records = []
    for item in source.get("runtimes", []):
        status, installation = runtime_reference_status(item)
        path = item.get("path", "")
        records.append({
            "path": path,
            "relative_path": item.get("relative_path"),
            "reference_status": status,
            "installation_classification": installation,
            "runtime_owner": runtime_owner(path),
            "interpreter_executed": item.get("interpreter_executed") is True,
            "size_bytes": item.get("size_bytes"),
            "modified_ns": item.get("modified_ns"),
            "error": item.get("error"),
            "version": item.get("version"),
            "sys_path": item.get("sys_path"),
            "prefixes": item.get("prefixes"),
            "user_site_state": item.get("user_site_state"),
            "confidence": "high" if status == "actual_existing_executable_file" else "high_for_not_installed_classification",
            "evidence_limit": "No interpreter was executed; version, sys.path, prefixes, and package activation remain unverified.",
        })
    records.sort(key=lambda item: casefold_path(item["path"]))

    packages = []
    for package in source.get("packages", []):
        owner = runtime_owner(package.get("site_packages", ""))
        packages.append({
            "name": package.get("name"),
            "version": package.get("version"),
            "metadata_path": package.get("metadata_path"),
            "site_packages": package.get("site_packages"),
            "runtime_owner": owner,
            "evidence_class": "static_live_source",
            "activation_verified": False,
        })
    packages.sort(key=lambda item: (
        item["runtime_owner"].casefold(), str(item.get("name") or "").casefold(), str(item.get("version") or "")
    ))

    status_counts = Counter(item["reference_status"] for item in records)
    owner_counts = Counter(item["runtime_owner"] for item in records if item["installation_classification"] == "installed_runtime_candidate")
    package_owner_counts = Counter(item["runtime_owner"] for item in packages)
    false_installed = [
        item for item in records
        if item["installation_classification"] == "installed_runtime_candidate"
        and item["reference_status"] != "actual_existing_executable_file"
    ]
    return {
        "schema": NORMALIZER_SCHEMA,
        "source_runtime_record_count": source.get("runtime_count"),
        "normalized_runtime_record_count": len(records),
        "actual_existing_executable_count": sum(
            1 for item in records if item["reference_status"] == "actual_existing_executable_file"
        ),
        "installed_runtime_candidates": [
            item for item in records if item["installation_classification"] == "installed_runtime_candidate"
        ],
        "not_installed_or_unresolved_count": sum(
            1 for item in records if item["installation_classification"] != "installed_runtime_candidate"
        ),
        "zero_unresolved_references_misreported_as_installed_runtimes": len(false_installed) == 0,
        "misreported_installed_runtime_records": false_installed,
        "reference_status_counts": dict(sorted(status_counts.items())),
        "installed_owner_counts": dict(sorted(owner_counts.items())),
        "package_metadata_count": len(packages),
        "package_owner_counts": dict(sorted(package_owner_counts.items())),
        "runtime_records": records,
        "packages": packages,
        "runtime_execution_performed": False,
        "missing_runtime_evidence": [
            "Exact interpreter versions were not executed or verified in V1A-1.",
            "sys.path, prefixes, user-site state, and import origins remain unverified.",
            "Launcher-to-runtime resolution remains static and may include environment-variable branches.",
        ],
    }


def classify_reusable(source: dict[str, Any], protected: set[str]) -> dict[str, Any]:
    records = []
    for item in source.get("components", []):
        path = item.get("path", "")
        info = classify_path(path, suffix=item.get("suffix"), protected=casefold_path(path) in protected)
        records.append({
            "path": path,
            "relative_path": item.get("relative_path"),
            "parse_status": item.get("parse_status"),
            "definition_count": len(item.get("definitions", [])),
            "import_count": len(item.get("imports", [])),
            "path_classification": info,
            "evidence_class": evidence_class_for(info, source_kind="static_source"),
        })
    records.sort(key=lambda item: casefold_path(item["path"]))
    return {
        "count": len(records),
        "live_source_candidate_count": sum(1 for item in records if item["evidence_class"] == "static_live_source"),
        "known_good_or_historical_count": sum(1 for item in records if item["evidence_class"] == "known_good_baseline"),
        "records": records,
        "import_edge_count": len(source.get("import_edges", [])),
        "source_imported_or_executed": source.get("source_imported_or_executed") is True,
    }


def classify_storage(source: dict[str, Any], protected: set[str]) -> dict[str, Any]:
    def convert(items: list[dict[str, Any]], source_kind: str = "observed_metadata") -> list[dict[str, Any]]:
        result = []
        for item in items:
            path = item.get("path", "")
            info = classify_path(path, suffix=item.get("suffix"), protected=casefold_path(path) in protected)
            record = dict(item)
            record["path_classification"] = info
            record["evidence_class"] = evidence_class_for(info, source_kind=source_kind)
            result.append(record)
        result.sort(key=lambda item: casefold_path(item.get("path")))
        return result

    models = convert(source.get("model_files", []))
    databases = convert(source.get("database_and_index_files", []))
    roots = convert(source.get("classified_storage_roots", []))
    return {
        "models": models,
        "databases_and_indexes": databases,
        "storage_roots": roots,
        "model_count": len(models),
        "database_and_index_count": len(databases),
        "storage_root_count": len(roots),
        "model_coverage_complete": False,
        "database_coverage_complete": False,
        "coverage_warning": "V1A-0 reached bounded scan caps; these records are observed evidence, not a complete installation inventory.",
    }


def classify_missions(source: dict[str, Any]) -> dict[str, Any]:
    records = []
    for item in source.get("records", []):
        path = item.get("path", "")
        info = classify_path(path, suffix=item.get("suffix"))
        records.append({
            "path": path,
            "relative_path": item.get("relative_path"),
            "mission_id": item.get("mission_id"),
            "result": item.get("result"),
            "parse_status": item.get("parse_status"),
            "path_classification": info,
            "evidence_class": "historical_receipt" if "receipt" in info["categories"] else "observed_live",
            "similarity_is_not_proof": True,
        })
    records.sort(key=lambda item: (str(item.get("mission_id") or ""), casefold_path(item["path"])))
    return {
        "record_count": len(records),
        "original_receipts_modified": False,
        "similarity_is_not_proof": True,
        "records": records,
    }


def verify_protected_candidates(manifest: dict[str, Any]) -> dict[str, Any]:
    records = []
    all_match = True
    for item in manifest.get("protected_candidates", []):
        path_text = item.get("path", "")
        expected = item.get("sha256")
        record = {
            "path": path_text,
            "expected_sha256": expected,
            "expected_size_bytes": item.get("size_bytes"),
            "status": "not_checked",
        }
        path = Path(path_text)
        try:
            if not path.is_file():
                record["status"] = "missing"
                all_match = False
            elif path.stat().st_size > MAX_HASH_BYTES:
                record["status"] = "hash_skipped_over_limit"
                all_match = False
            else:
                actual = sha256_file(path, MAX_HASH_BYTES)
                record["actual_sha256"] = actual
                record["actual_size_bytes"] = path.stat().st_size
                record["status"] = "match" if expected and actual.casefold() == str(expected).casefold() else "mismatch"
                if record["status"] != "match":
                    all_match = False
        except (OSError, PermissionError, ValueError) as exc:
            record["status"] = "error"
            record["error"] = f"{type(exc).__name__}:{exc}"
            all_match = False
        records.append(record)
    return {"all_match": all_match, "records": records}


def build_missing_evidence(data: dict[str, Any], runtime_report: dict[str, Any], storage: dict[str, Any], launcher_report: dict[str, Any]) -> dict[str, Any]:
    source_missing = []
    for name in ("GAPS_AND_WARNINGS.json", "LIVE_STATIC_MANIFEST.json", "PYTHON_RUNTIME_STATIC_MAP.json"):
        source_missing.extend(data[name].get("missing_evidence", []))
    source_warnings = []
    for name in REQUIRED_INPUTS:
        value = data[name]
        if isinstance(value, dict):
            source_warnings.extend(value.get("warnings", []))

    normalized_missing = [
        {
            "area": "Python runtime behavior",
            "status": "missing",
            "reason": "Interpreter execution was intentionally deferred; exact versions, sys.path, prefixes, user-site state, and import origins are not established.",
            "recommended_future_phase": "V1A-3",
        },
        {
            "area": "Launcher execution graph",
            "status": "partial_static_evidence",
            "reason": "Launcher text is available, but environment-variable expansion, CALL/START flow resolution, shortcut targets, working directories, and runtime activation branches are not normalized yet.",
            "recommended_future_phase": "V1A-2",
        },
        {
            "area": "Complete model inventory",
            "status": "missing",
            "reason": "Only bounded observed model files are present in V1A-0. The broader GGUF model library was not captured.",
            "recommended_future_phase": "bounded_storage_followup",
        },
        {
            "area": "Live Bibliotheca database",
            "status": "missing",
            "reason": "Observed database records are backups; the live database was not captured in V1A-0.",
            "recommended_future_phase": "bounded_storage_followup",
        },
        {
            "area": "Windows evidence bridge",
            "status": "not_collected_in_v1a0",
            "reason": "Processes, services, tasks, ports, signatures, installed applications, event failures, and resource deltas require a separate read-only phase.",
            "recommended_future_phase": "V1A-4",
        },
    ]
    return {
        "schema": NORMALIZER_SCHEMA,
        "source_missing_evidence": sorted(set(str(item) for item in source_missing)),
        "source_warnings": sorted(set(str(item) for item in source_warnings)),
        "normalized_missing_evidence": normalized_missing,
        "coverage_limits": {
            "launcher_records_normalized": launcher_report["unique_path_count"],
            "runtime_records_normalized": runtime_report["normalized_runtime_record_count"],
            "models_observed": storage["model_count"],
            "databases_or_indexes_observed": storage["database_and_index_count"],
            "scan_caps_were_reached": any("limit_reached" in str(item) for item in source_warnings),
        },
        "agent_rule": "Missing, denied, unresolved, partial, historical, and inferred evidence must never be reported as current proof.",
    }


