def write_json(output_dir: Path, name: str, value: Any) -> dict[str, Any]:
    raw = pretty_bytes(value)
    path = output_dir / name
    path.write_bytes(raw)
    return {"name": name, "size_bytes": len(raw), "sha256": sha256_bytes(raw)}


def output_total(output_dir: Path) -> int:
    return sum(path.stat().st_size for path in output_dir.iterdir() if path.is_file())


def run_normalizer(input_dir: Path, output_dir: Path, mission_id: str, project_root: Path) -> dict[str, Any]:
    if output_dir.exists() and any(output_dir.iterdir()):
        raise FileExistsError(f"output_directory_must_be_empty:{output_dir}")
    output_dir.mkdir(parents=True, exist_ok=True)

    data, input_hashes_before = load_inputs(input_dir)
    verify_input_contract(data)
    manifest = data["LIVE_STATIC_MANIFEST.json"]
    protected = protected_path_set(manifest)

    top = normalize_top_level(manifest, protected)
    launcher_report = classify_launchers(data["LAUNCHER_TRACE_CANDIDATES.json"], protected)
    runtime_report = classify_runtimes(data["PYTHON_RUNTIME_STATIC_MAP.json"])
    reusable = classify_reusable(data["REUSABLE_COMPONENTS_MAP.json"], protected)
    storage = classify_storage(data["MODEL_DATABASE_AND_STORAGE_MAP.json"], protected)
    missions = classify_missions(data["MISSION_EVIDENCE_INDEX.json"])
    protected_verification = verify_protected_candidates(manifest)
    if not protected_verification["all_match"]:
        raise RuntimeError("protected_candidate_hash_verification_failed")

    normalized_manifest = {
        "schema": "foxai.agent_fox.technical_core.v1a1.normalized_static_manifest.v1",
        "mission_id": mission_id,
        "source_mission_id": data["AUDIT_RECEIPT.json"].get("mission_id"),
        "source_audit_result": data["AUDIT_RECEIPT.json"].get("result"),
        "project_root": norm_win(project_root),
        "evidence_contract_schema": CONTRACT_SCHEMA,
        "normalizer_schema": NORMALIZER_SCHEMA,
        "deterministic_output": True,
        "network_used": False,
        "packages_installed": False,
        "source_or_launcher_execution": False,
        "runtime_probe_execution": False,
        "models_loaded": False,
        "existing_foxai_source_modified": False,
        "top_level_inventory": top,
        "launchers_summary": {
            key: launcher_report[key]
            for key in (
                "source_launcher_count", "unique_path_count", "root_level_count", "live_candidate_count",
                "historical_or_derived_count", "primary_category_counts", "evidence_class_counts"
            )
        },
        "runtime_summary": {
            key: runtime_report[key]
            for key in (
                "source_runtime_record_count", "normalized_runtime_record_count", "actual_existing_executable_count",
                "not_installed_or_unresolved_count", "zero_unresolved_references_misreported_as_installed_runtimes",
                "reference_status_counts", "installed_owner_counts", "package_metadata_count", "package_owner_counts"
            )
        },
        "reusable_components": reusable,
        "storage": storage,
        "mission_evidence": missions,
        "declared_manifests_and_configs": data["MANIFEST_AND_CONFIG_MAP.json"],
        "repository_reference": manifest.get("repository_reference"),
        "protected_candidate_verification": protected_verification,
        "capability_boundaries": {
            "can_classify_static_evidence": True,
            "can_normalize_records_present_in_v1a0": True,
            "can_execute_repairs": False,
            "can_claim_complete_runtime_behavior": False,
            "can_claim_complete_model_or_database_inventory": False,
            "similarity_is_proof": False,
        },
    }
    missing = build_missing_evidence(data, runtime_report, storage, launcher_report)
    coverage = build_coverage(data, top, launcher_report, runtime_report, reusable, storage, missions)

    outputs = []
    outputs.append(write_json(output_dir, "NORMALIZED_WHOLE_FOXAI_STATIC_MANIFEST.json", normalized_manifest))
    outputs.append(write_json(output_dir, "LAUNCHER_CLASSIFICATION_REPORT.json", launcher_report))
    outputs.append(write_json(output_dir, "RUNTIME_REFERENCE_REPORT.json", runtime_report))
    outputs.append(write_json(output_dir, "COVERAGE_REPORT.json", coverage))
    outputs.append(write_json(output_dir, "MISSING_EVIDENCE_REPORT.json", missing))

    input_hashes_after = {name: sha256_file(input_dir / name, MAX_INPUT_FILE_BYTES) for name in REQUIRED_INPUTS}
    if input_hashes_before != input_hashes_after:
        raise RuntimeError("source_evidence_changed_during_normalization")
    if not runtime_report["zero_unresolved_references_misreported_as_installed_runtimes"]:
        raise RuntimeError("unresolved_runtime_reference_misreported_as_installed")

    receipt = {
        "schema": "foxai.agent_fox.technical_core.v1a1.normalization_receipt.v1",
        "mission_id": mission_id,
        "source_mission_id": data["AUDIT_RECEIPT.json"].get("mission_id"),
        "result": "normalized_static_manifest_complete",
        "input_directory": norm_win(input_dir),
        "output_directory": norm_win(output_dir),
        "input_sha256": dict(sorted(input_hashes_after.items())),
        "source_evidence_unchanged": True,
        "protected_candidates_unchanged": True,
        "network_used": False,
        "packages_installed": False,
        "runtime_probes_executed": False,
        "foxai_source_or_launchers_executed": False,
        "models_loaded": False,
        "existing_foxai_source_modified": False,
        "actual_existing_python_executable_count": runtime_report["actual_existing_executable_count"],
        "unresolved_runtime_references_misreported_as_installed": 0,
        "core_outputs_before_receipt": outputs,
    }
    receipt_meta = write_json(output_dir, "NORMALIZATION_RECEIPT.json", receipt)
    total = output_total(output_dir)
    if total > MAX_OUTPUT_BYTES:
        raise RuntimeError(f"output_ceiling_exceeded:{total}")
    return {
        "result": receipt["result"],
        "mission_id": mission_id,
        "output_directory": norm_win(output_dir),
        "output_total_bytes": total,
        "normalization_receipt": receipt_meta,
        "actual_existing_python_executable_count": runtime_report["actual_existing_executable_count"],
        "unresolved_runtime_references_misreported_as_installed": 0,
        "protected_candidates_unchanged": True,
        "network_used": False,
        "existing_foxai_source_modified": False,
    }


